import java.util.ArrayList;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        int n = 5; // nodes 0 through 4
        List<List<Integer>> adjList = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adjList.add(new ArrayList<>());
        }

        // Undirected edges: 0-1, 0-2, 1-3, 2-4
        addEdge(adjList, 0, 1);
        addEdge(adjList, 0, 2);
        addEdge(adjList, 1, 3);
        addEdge(adjList, 2, 4);

        System.out.println(adjList);
    }

    static void addEdge(List<List<Integer>> adjList, int u, int v) {
        adjList.get(u).add(v);
        adjList.get(v).add(u); // undirected -- both directions
    }
}

public class Main {
    public static void main(String[] args) {
        int n = 5;
        int[][] adjMatrix = new int[n][n];

        addEdge(adjMatrix, 0, 1);
        addEdge(adjMatrix, 0, 2);
        addEdge(adjMatrix, 1, 3);
        addEdge(adjMatrix, 2, 4);

        for (int[] row : adjMatrix) {
            System.out.println(java.util.Arrays.toString(row));
        }
    }

    static void addEdge(int[][] adjMatrix, int u, int v) {
        adjMatrix[u][v] = 1;
        adjMatrix[v][u] = 1;
    }
}

